import { FaceDetector, FilesetResolver, ImageSegmenter } from '@mediapipe/tasks-vision';

import rawr from 'rawr';

const params = new URLSearchParams(self.location.search);
let workerDirectory = params.get('worker-directory');

if (!workerDirectory) {
  workerDirectory = '/public';
} else if (workerDirectory[0] === '/') {
  workerDirectory = workerDirectory.slice(1);
}

const rawrPeer = rawr({ transport: rawr.transports.worker() });
self.rawrPeer = rawrPeer;

function logToApp(msg) {
  if (msg && typeof msg === 'object') {
    msg.timestamp = Date.now();
    rawrPeer.notifiers.log(msg);
    return;
  }
  rawrPeer.notifiers.log({ msg, timestamp: Date.now() });
}

function logErrorToApp(err) {
  rawrPeer.notifiers.log({ error: err.message, stack: err.stack, timestamp: Date.now() });
}

self.onerror = (err) => { 
  console.log('error in worker', err);
  logErrorToApp(err);
};

let loadStep = 0;
function logLoadStep(msg) {
  loadStep++;
  logToApp(`Load step ${loadStep}: ${msg}`);
}

async function startWorker() {
  const runningMode = 'IMAGE';
  let vitalsAlg;
  let vitalsModule;
  let frame_bytes_front;
  let frame_bytes_rear;
  let frame_bytes_segmentation;
  // Added to prevent mainRun from being called multiple times
  let mainRunExecuted = false;

  let faceDetector;
  const bboxHeightAdjustment = 30.0;
  let imageSegmenter;
  let segmentationMask;
  let delegateType;
  let wasmEnvReport = null;
  let wasmEnvReported = false;

  const offscreenCanvas = new OffscreenCanvas(1, 1);
  const offscreenCtx = offscreenCanvas.getContext('2d', { willReadFrequently: true });

  const modelsPrefix = 'models/';

  async function getWasmEnvReport() {
    const memoryEstimate = await (navigator.storage?.estimate?.() || {});
    const jsHeapSizeLimit = performance.memory?.jsHeapSizeLimit || null;

    let wasmLoopDuration = null;
    let wasmBenchmarkError = null;

    try {
      const code = new Uint8Array([
        // Header
        0x00, 0x61, 0x73, 0x6D,       // \0asm
        0x01, 0x00, 0x00, 0x00,       // version 1

        // Type section
        0x01, 0x05, 0x01,             // section 1 (type), length 5, 1 entry
          0x60, 0x00, 0x01, 0x7F,     // func type: () → i32

        // Function section
        0x03, 0x02, 0x01, 0x00,       // section 3 (function), length 2, 1 func of type 0

        // Export section
        0x07, 0x07, 0x01,             // section 7 (export), length 7, 1 export
          0x03, 0x66, 0x6E, 0x31,     // name "fn1"
          0x00, 0x00,                 // kind: function, index 0

        // Code section
        0x0A, 0x06, 0x01,             // section 10 (code), length 6, 1 function
          0x04, 0x00,                 // func body size 4, 0 locals
            0x41, 0x2A, 0x0B          // i32.const 42, end
      ]);

      const mod = await WebAssembly.compile(code);
      const inst = await WebAssembly.instantiate(mod);
      const fn = inst.exports.fn1;

      const t0 = performance.now();
      for (let i = 0; i < 1e6; i++) fn();
      const t1 = performance.now();

      wasmLoopDuration = t1 - t0;
    } catch (err) {
      wasmBenchmarkError = err instanceof Error ? err.message : String(err);
    }

    return {
      wasmSupported: typeof WebAssembly !== 'undefined',
      wasmThreads: typeof SharedArrayBuffer !== 'undefined' && crossOriginIsolated === true,
      deviceMemoryGB: navigator.deviceMemory || null,
      logicalProcessors: navigator.hardwareConcurrency || null,
      jsHeapSizeLimit,
      storageEstimate: {
        quota: memoryEstimate.quota || null,
        usage: memoryEstimate.usage || null
      },
      userAgent: navigator.userAgent,
      platform: navigator.platform,
      wasm1MCallsDurationMs: wasmLoopDuration,
      wasmBenchmarkError,
      likelyJITDisabled: wasmLoopDuration !== null && wasmLoopDuration > 100
    };
  }

  async function loadWasmModule() {
    // const module = await import(`/${workerDirectory}/webvital.js`);
    const module = await import(/* @vite-ignore */`/${workerDirectory}/webvital.js`);
    return module.default();
  }

  function mainRun() {
    if (mainRunExecuted) {
      return;
    }

    mainRunExecuted = true;
    vitalsAlg = undefined;

    vitalsAlg = new vitalsModule.WebVital(modelsPrefix);
  }

  async function detectVitals(frameInfo, imgBitmap) {
    offscreenCanvas.width = imgBitmap.width;
    offscreenCanvas.height = imgBitmap.height;
    offscreenCtx.drawImage(imgBitmap, 0, 0);
    const imgData = offscreenCtx.getImageData(0, 0, imgBitmap.width, imgBitmap.height);
    imgBitmap.close();

    const rows = frameInfo.height;
    const cols = frameInfo.width;

    // Get required inputs from algorithm
    const inputs = vitalsAlg.requiredInputs();
    // interate through required inputs
    for (let i = 0; i < inputs.size(); i++) {
      const input = inputs.get(i);
      if (input === 'frame_image') {
        frame_bytes_front = frameBytesToHeap(imgData.data, frame_bytes_front);
        const frame_ptr = frame_bytes_front.byteOffset;
        vitalsAlg.setFrameImage(input, frame_ptr, rows, cols, frameInfo.timestamp);
      }
      else if (input === 'frame_segmentation') {
        const start = performance.now();
        
        segmentImage(imgData);
        if (segmentationMask) 
        {
          frame_bytes_segmentation = frameBytesToHeap(segmentationMask, frame_bytes_segmentation);
          const segmentation_ptr = frame_bytes_segmentation.byteOffset;
          vitalsAlg.setSegmentation(input, segmentation_ptr, rows, cols, frameInfo.timestamp);
        }

        const segDuration = Math.round(performance.now() - start);
        rawrPeer.notifiers.segDuration({duration: segDuration, timestamp: frameInfo.timestamp});
      }
      else if (input === 'frame_detectedFaceRoi') {
        const faceStart = performance.now();
        const faceRect = detectFace(imgData);
        const faceDuration = Math.round(performance.now() - faceStart);
        rawrPeer.notifiers.faceDuration({duration: faceDuration, timestamp: frameInfo.timestamp});
        vitalsAlg.setFace(input, faceRect, frameInfo.timestamp);
      }
    }

    const start = performance.now();
    const signs = JSON.parse(vitalsAlg.processFrame(frameInfo.timestamp));
    const duration = Math.round(performance.now() - start);

    // Send signs through rawr notifications
    rawrPeer.notifiers.signs({ ...signs, duration, timestamp: frameInfo.timestamp });
    return 1;
  }

  function getVersionString() {
    return vitalsAlg.getVersionString();
  }

  function startSession(sessionTagsStr) {
    if (!wasmEnvReported && wasmEnvReport) {
      wasmEnvReported = true;
      logToApp({ wasmEnvReport });
    }
    vitalsAlg.startSession(sessionTagsStr);
  }

  function endSession() {
    return vitalsAlg.endSession();
  }

  function previewSession() { 
    vitalsAlg.previewSession();
  }

  function getRunToken() {
    return vitalsAlg.getRunToken();
  }

  function authorizeVitals(token) {
    const auth = vitalsAlg.authorizeVitals(token);
    logToApp({ msg: 'Authorization result', auth });
    return auth;
  }

  function setExtendedLogs(extendedLogsEnabled) {
    vitalsAlg.setExtendedLogs(extendedLogsEnabled);
  }

  async function setFaceGuide(faceGuide) {
    // convert face guide to cvRect
    const faceGuideRect = new vitalsModule.cvRect();
    faceGuideRect.x = faceGuide.x;
    faceGuideRect.y = faceGuide.y;
    faceGuideRect.width = faceGuide.width;
    faceGuideRect.height = faceGuide.height;

    vitalsAlg.setFaceGuide(faceGuideRect);
  }

  function frameBytesToHeap(imgDataArray, frame_bytes) {
    if (!frame_bytes) {
      frame_bytes = arrayToHeap(imgDataArray);
    } else if (frame_bytes.length !== imgDataArray.length) {
      freeArray(frame_bytes);
      frame_bytes = arrayToHeap(imgDataArray);
    } else {
      frame_bytes.set(imgDataArray);
    }
    return frame_bytes;
  }

  function freeArray(heapBytes) {
    vitalsModule._free(heapBytes.byteOffset);
  }

  function arrayToHeap(typedArray) {
    const numBytes = typedArray.length * typedArray.BYTES_PER_ELEMENT;
    const ptr = vitalsModule._malloc(numBytes);
    const heapBytes = new Uint8Array(vitalsModule.HEAPU8.buffer, ptr, numBytes);
    heapBytes.set(typedArray);
    return heapBytes;
  }

  // ------------------------------
  // Mediapipe Tasks Vision Loader and Runner
  // ------------------------------
  async function loadMediapipeModules() {
    console.log('Initializing Image Segmenter ...');
    const initializationStartTime = Date.now();
    logLoadStep('Mediapipe Tasks Vision module loaded');
    const vision = await FilesetResolver.forVisionTasks(`/${workerDirectory}/@mediapipe/tasks-vision/wasm`);
    logLoadStep('Mediapipe Tasks Vision fileset resolved');

    // Determine if GPU delegate is available via WebGL context
    const testCanvas = new OffscreenCanvas(1, 1);
    const gl = testCanvas.getContext('webgl2') || testCanvas.getContext('webgl');
    delegateType = gl ? 'GPU' : 'CPU';
    console.log(`Mediapipe delegate chosen: ${delegateType}`);
    try {
      wasmEnvReport = await getWasmEnvReport();
      logLoadStep('WASM Environment Report generated');
      console.log('WASM Environment Report:', wasmEnvReport);
      wasmEnvReport.delegateType = delegateType;
    } catch (e) {
      console.error('Error initializing Mediapipe Tasks Vision:', e);
    }

    imageSegmenter = await ImageSegmenter.createFromOptions(vision, {
          baseOptions: {
            modelAssetPath: `/${workerDirectory}/selfie_multiclass_256x256.tflite`,
            delegate: delegateType
          },
          runningMode: runningMode,
          outputCategoryMask: true,
          outputConfidenceMasks: false,
          canvas: new OffscreenCanvas(640, 640)
        });
    logLoadStep('Image Segmenter created');
    faceDetector = await FaceDetector.createFromOptions(vision, {
          baseOptions: {
            modelAssetPath: `/${workerDirectory}/blaze_face_short_range.tflite`,
            delegate: delegateType
          },
          runningMode: runningMode,
          minDetectionConfidence: 0.6,
          canvas: new OffscreenCanvas(640, 640)
        });
    logLoadStep('Face Detector created');
    console.log(`Mediapipe initialized in ${Date.now() - initializationStartTime} ms`);
  }

  function segmentImage(imgData, asPromise = false)
  {
    if (imageSegmenter === undefined) { return null; }
    if (asPromise) {
      return new Promise((resolve) => {
        imageSegmenter.segment(imgData, (result) => {
          resolve(result.categoryMask.getAsUint8Array());
        });
      });
    }
    imageSegmenter.segment(imgData, segmentationCallback);
  }

  function segmentationCallback(result) {
    if (!result || !result.categoryMask) {
      console.warn("No segmentation result received. No face was segmented.");
      segmentationMask = null;
      return;
    }

    segmentationMask = result.categoryMask.getAsUint8Array();
  }

  function detectFace(imgData)
  {
    let faceRect = new vitalsModule.cvRect();
    if (faceDetector === undefined) return faceRect;
    const faceDetectorResults = faceDetector.detect(imgData);
    if (faceDetectorResults.detections && faceDetectorResults.detections.length > 0)
    {
      let box = faceDetectorResults.detections[0].boundingBox;
      faceRect.x = box.originX;
      faceRect.y = box.originY;
      faceRect.width = box.width;
      faceRect.height = box.height;
    }
    
    return faceRect;
  }


  try {
    vitalsModule = await loadWasmModule();
    logLoadStep('Wasm module loaded');
    await loadMediapipeModules();
    logLoadStep('Mediapipe modules loaded');
  } catch (err) {
    console.error('Error loading Wasm module:', err);
    logErrorToApp(err);
    // try again after a short delay
    try {
      await new Promise(resolve => setTimeout(resolve, 100));
      vitalsModule = await loadWasmModule();
      logLoadStep('Wasm module loaded on second attempt');
    } catch (err) {
      console.error('Error loading Wasm module on second attempt:', err);
      logErrorToApp(err);
      throw err;
    }
  }

  rawrPeer.addHandler('mainRun', mainRun);
  rawrPeer.addHandler('detectVitals', detectVitals);
  rawrPeer.addHandler('getVersionString', getVersionString);
  rawrPeer.addHandler('startSession', startSession);
  rawrPeer.addHandler('endSession', endSession);
  rawrPeer.addHandler('previewSession', previewSession);
  rawrPeer.addHandler('getRunToken', getRunToken);
  rawrPeer.addHandler('authorizeVitals', authorizeVitals);
  rawrPeer.addHandler('setExtendedLogs', setExtendedLogs);
  rawrPeer.addHandler('setFaceGuide', setFaceGuide);
  rawrPeer.addHandler('segmentImage', segmentImage);
  rawrPeer.addHandler('detectFace', detectFace);
  rawrPeer.notifications.ondetectVitals(detectVitals);

  mainRun();
  console.log('Required worker modules initialized');
  rawrPeer.notifiers.ready('ok');
}
console.log('Worker script loaded');
logLoadStep('Worker parsed');

startWorker().then(() => {
  logLoadStep('Worker started');
  console.log('Worker started');
}).catch((err) => {
  console.error('Error starting worker:', err);
  logErrorToApp(err);
});
